[Form]
public class ETGPaymentUploader extends FormRun
{
    ModuleCustVend moduleCustVend;

}

/// <summary>
///
/// </summary>
public void init()
{
    moduleCustVend = element.args().parmEnum();

    super();
}

/// <summary>
///
/// </summary>
public void custSettleTransaction()
{
    MultiSelectionHelper        selectionHelper = MultiSelectionHelper::construct();//Create instance of class
    Set                         selectedRecords = new Set(Types::Record);//Declare a set of type record
    NumberSequenceReference     numberSequenceReference;
    ETGSettlementNumberSequence numSeq;

    ETGPaymentUploaderTable     custPaymentUpload, custPaymentUploadLoc, custPaymentUploadNxt, custPaymentUploadSeq;
    CustTrans                   invCustTrans, payCustTrans;
    CustTransOpen               invCustTransOpen, payCustTransOpen;
    real                        invSettle, paySettle;
    SpecTransExecutionContext   specTransExecutionContext;
    SpecTransManager            specTransManager;
    TransDate                   settlementDate;
    int                         settleNum, settleNumPost, invoiceCount = 0, payCount = 0;
    CustTransSettleTransactionParameters    parameter = CustTransSettleTransactionParameters::construct();

    selectionHelper.parmDataSource(ETGPaymentUploaderTable_ds);   //Set the datasource

    custPaymentUploadNxt = selectionHelper.getFirst();

    if(custPaymentUploadNxt.RecId)
    {
        ttsbegin;
        while(custPaymentUploadNxt)
        {
            if(custPaymentUploadNxt.SettlementNumber != settleNum)
            {
                specTransExecutionContext = SpecTransExecutionContext::newFromSource(CustTable::find(custPaymentUploadNxt.AccountNum));
                specTransManager = SpecTransManager::construct(specTransExecutionContext.parmSpecContext());
                invoiceCount = 0;
                payCount = 0;
                while select custPaymentUpload 
                    where custPaymentUpload.SettlementNumber == custPaymentUploadNxt.SettlementNumber &&
                    !custPaymentUpload.SettlementNumberSequence
                {
                        if(custPaymentUpload.Validated && !custPaymentUpload.Posted )
                        {
                            select firstonly invCustTrans
                                where invCustTrans.Voucher == custPaymentUpload.Voucher &&
                                    invCustTrans.AmountCur > 0
                                join invCustTransOpen
                                where invCustTransOpen.RefRecId == invCustTrans.RecId;

                            if(invCustTransOpen)
                            {
                                invoiceCount++;
                                invSettle = custPaymentUpload.SettlementAmount;
                                settlementDate = custPaymentUpload.SettlementDate;
                                specTransManager.insert(invCustTransOpen.dataAreaId, invCustTransOpen.TableId, invCustTransOpen.RecId, invSettle, invCustTrans.CurrencyCode);
                            }

                            select firstonly payCustTrans
                                where payCustTrans.Voucher == custPaymentUpload.Voucher &&
                                    payCustTrans.AmountCur < 0
                                join payCustTransOpen
                                where payCustTransOpen.RefRecId == payCustTrans.RecId;

                            if(payCustTransOpen)
                            {
                                payCount++;
                                paySettle = custPaymentUpload.SettlementAmount;
                                specTransManager.insert(payCustTransOpen.dataAreaId, payCustTransOpen.TableId, payCustTransOpen.RecId, paySettle, payCustTrans.CurrencyCode);
                            }
                            settleNum = custPaymentUpload.SettlementNumber;
                        }
                        else
                        {
                            throw Error(strFmt("@ETG_New:PaymentUploaderSettleTransac",custPaymentUpload.Voucher,custPaymentUpload.SettlementNumber));
                        }

                }
                parameter.saveDatePrinciple = SettleDatePrinc::SelectDate;
                parameter.saveDate = settlementDate;
                if(invoiceCount > 0 && payCount > 0)
                {
                    if(CustTrans::settleTransaction(specTransExecutionContext,parameter))
                    {
                        numberSequenceReference = NumberSeqReference::findReference(extendedTypeNum(ETGSettlementNumberSequence));
                        if(numberSequenceReference)
                        {
                            numSeq = NumberSeq::newGetNum(numberSequenceReference).num();
                        }
                        while select custPaymentUploadLoc 
                            where custPaymentUploadLoc.SettlementNumber == settleNum &&
                            !custPaymentUploadLoc.SettlementNumberSequence
                        {
                            custPaymentUploadLoc.selectForUpdate(true);
                            custPaymentUploadLoc.Posted = NoYes::Yes;
                            custPaymentUploadLoc.SettlementNumberSequence = numSeq;
                            custPaymentUploadLoc.update();
                        }
                    }
                }
            }
            custPaymentUploadNxt = selectionHelper.getNext();
        }
    }
    else
    {
        throw Error(strFmt("@ETG_New:PaymentUploaderTransactionSettlement"));
    }
    Info("@ETG_New:PaymentUploaderTransactionPosted");
    ttscommit;
    ETGPaymentUploaderTable_ds.research(true);
}

/// <summary>
///
/// </summary>
public void vendSettleTransaction()
{
    MultiSelectionHelper        selectionHelper = MultiSelectionHelper::construct();//Create instance of class
    Set                         selectedRecords = new Set(Types::Record);//Declare a set of type record
    NumberSequenceReference     numberSequenceReference;
    ETGSettlementNumberSequence numSeq;

    ETGPaymentUploaderTable     vendPaymentUpload, vendPaymentUploadLoc, vendPaymentUploadNxt, vendPaymentUploadSeq;
    VendTable                   vendTableSettle;
    VendTrans                   invVendTrans, payVendTrans;
    VendTransOpen               invVendTransOpen, payVendTransOpen;
    real                        invSettle, paySettle;
    CustVendTransData           vendTransData;
    CustVendOpenTransManager    vendManager;
    TransDate                   settlementDate;
    int                         settleNum, invoiceCount = 0, payCount = 0;

    selectionHelper.parmDataSource(ETGPaymentUploaderTable_ds);   //Set the datasource

    vendPaymentUploadNxt = selectionHelper.getFirst();

    if(vendPaymentUploadNxt.RecId)
    {
        ttsbegin;
        while(vendPaymentUploadNxt)
        {
            if(vendPaymentUploadNxt.SettlementNumber != settleNum)
            {
                vendTableSettle = VendTable::find(vendPaymentUploadNxt.AccountNum);
                vendManager = CustVendOpenTransManager::construct(vendTableSettle);
                invoiceCount = 0;
                payCount = 0;
                while select vendPaymentUpload 
                    where vendPaymentUpload.SettlementNumber == vendPaymentUploadNxt.SettlementNumber &&
                    !vendPaymentUpload.SettlementNumberSequence
                {
                    if(vendPaymentUpload.Validated && !vendPaymentUpload.Posted )
                    {
                        select firstonly invVendTrans
                        where invVendTrans.Voucher == vendPaymentUpload.Voucher &&
                            invVendTrans.AmountCur < 0
                        join invVendTransOpen
                        where invVendTransOpen.RefRecId == invVendTrans.RecId;

                        if(invVendTransOpen)
                        {
                            invoiceCount++;
                            settlementDate  = vendPaymentUpload.SettlementDate;
                            invSettle       = vendPaymentUpload.SettlementAmount;
                            vendManager.updateTransMarked(invVendTransOpen,true);
                            vendManager.updateSettleAmount(invVendTransOpen, invSettle);
                            vendTransData = CustVendTransData::construct(invVendTrans);
                            vendTransData.markForSettlement(vendTableSettle);
                        }

                        select firstonly payVendTrans
                        where payVendTrans.Voucher == vendPaymentUpload.Voucher &&
                            payVendTrans.AmountCur > 0
                        join payVendTransOpen
                        where payVendTransOpen.RefRecId == payVendTrans.RecId;

                        if(payVendTransOpen)
                        {
                            payCount++;
                            paySettle       = vendPaymentUpload.SettlementAmount;
                            vendManager.updateTransMarked(payVendTransOpen,true);
                            vendManager.updateSettleAmount(payVendTransOpen, paySettle);
                            vendTransData = CustVendTransData::construct(payVendTrans);
                            vendTransData.markForSettlement(vendTableSettle);
                        }
                        settleNum = vendPaymentUpload.SettlementNumber;
                    }
                    else
                    {
                        throw Error(strFmt("@ETG_New:PaymentUploaderSettleTransac",vendPaymentUpload.Voucher,vendPaymentUpload.SettlementNumber));
                    }
                }
                if(invoiceCount > 0 && payCount > 0)
                {
                    if(VendTrans::settleTransact(vendTableSettle, null, true, SettleDatePrinc::SelectDate, settlementDate))
                    {
                        numberSequenceReference = NumberSeqReference::findReference(extendedTypeNum(ETGSettlementNumberSequence));
                        if(numberSequenceReference)
                        {
                            numSeq = NumberSeq::newGetNum(numberSequenceReference).num();
                        }
                            while select vendPaymentUploadLoc 
                                where vendPaymentUploadLoc.SettlementNumber == settleNum &&
                                !vendPaymentUploadLoc.SettlementNumberSequence
                            {
                                vendPaymentUploadLoc.selectForUpdate(true);
                                vendPaymentUploadLoc.Posted = NoYes::Yes;
                                vendPaymentUploadLoc.SettlementNumberSequence = numSeq;
                                vendPaymentUploadLoc.update();
                            }
                    }
                }
            }
            vendPaymentUploadNxt = selectionHelper.getNext();
        }
    }
    else
    {
        throw Error(strFmt("@ETG_New:PaymentUploaderTransactionSettlement"));
    }
    info("@ETG_New:PaymentUploaderTransactionPosted");
    ttscommit;
    ETGPaymentUploaderTable_ds.research(true);
}

/// <summary>
///
/// </summary>
public void undoCustSettleTransaction()
{
    MultiSelectionHelper selectionHelper = MultiSelectionHelper::construct();//Create instance of class
    Set selectedRecords = new Set(Types::Record);//Declare a set of type record

    ETGPaymentUploaderTable     custPaymentUpload, custPaymentUploadLoc;
    CustTrans                   payCustTrans;
    CustSettlement              custSettlement;
    CustTable                   custTable;
    SpecTransManager            specTransManager;
    TransDate                   settlementDate;
    str                         settleSeqNum;
    boolean                     undo = false;

    selectionHelper.parmDataSource(ETGPaymentUploaderTable_ds);   //Set the datasource

    custPaymentUploadLoc = selectionHelper.getFirst();

    if(custPaymentUploadLoc.RecId)
    {
        ttsbegin;
        while(custPaymentUploadLoc)
        {
            if(custPaymentUploadLoc.SettlementNumberSequence != settleSeqNum)
            {
                while select custPaymentUpload 
                    where custPaymentUpload.SettlementNumberSequence == custPaymentUploadLoc.SettlementNumberSequence &&
                          custPaymentUpload.Posted && 
                          !custPaymentUpload.Reversed
                {
                    select firstonly payCustTrans where payCustTrans.Voucher == custPaymentUpload.Voucher;

                        settlementDate = custPaymentUploadLoc.SettlementDate;
                        select * from custSettlement
                                where custSettlement.TransRecId == payCustTrans.RecId &&
                                custSettlement.TransCompany  == payCustTrans.DataAreaId &&
                                custSettlement.AccountNum    == payCustTrans.AccountNum &&
                                custSettlement.CanBeReversed == NoYes::Yes &&
                                custSettlement.TransDate     == settlementDate;
                        {
                            custTable   = CustTable::find(payCustTrans.AccountNum);

                            specTransManager = SpecTransManager::newRefTableId(custTable, tablenum(custSettlement), true);

                            specTransManager.insert(custSettlement.DataAreaId
                                                    , custSettlement.TableId
                                                    , custSettlement.RecId
                                                    , custSettlement.SettleAmountCur
                                                    , payCustTrans.CurrencyCode);

                            custSettlement.CustVendSettlement::markThisAndRelatedOffsets(specTransManager, payCustTrans.CurrencyCode);

                            if (CustTrans::reverseTransact(custTable, null, settleDatePrinc::SelectDate, settlementDate))
                            {
                                specTransManager.deleteAll();
                                undo = true;
                            }
                        }

                    if(undo)
                    {
                        custPaymentUpload.selectForUpdate(true);
                        custPaymentUpload.Reversed = NoYes::Yes;
                        custPaymentUpload.update();
                    }
                    settleSeqNum = custPaymentUpload.SettlementNumberSequence;
                }
            }
            custPaymentUploadLoc = selectionHelper.getNext();
        }

    }
    else
    {
        throw error("@ETG_New:PaymentUploaderTransactionSettlement");
    }
    info("@ETG_New:PaymentUploaderUndoSettlement");
    ttscommit;
    ETGPaymentUploaderTable_ds.research(true);
}

/// <summary>
///
/// </summary>
public void undoVendSettleTransaction()
{
    MultiSelectionHelper selectionHelper = MultiSelectionHelper::construct();//Create instance of class
    Set selectedRecords = new Set(Types::Record);//Declare a set of type record

    ETGPaymentUploaderTable     vendPaymentUpload, vendPaymentUploadLoc;
    VendTrans                   payVendTrans;
    VendSettlement              vendSettlement;
    VendTable                   vendTable;
    SpecTransManager            specTransManager;
    TransDate                   settlementDate;
    str                         settleSeqNum;
    boolean                     undo = false;

    selectionHelper.parmDataSource(ETGPaymentUploaderTable_ds);   //Set the datasource

    vendPaymentUpload = selectionHelper.getFirst();

    if(vendPaymentUpload.RecId)
    {
        ttsbegin;
        while(vendPaymentUpload)
        {
            if(vendPaymentUpload.SettlementNumberSequence != settleSeqNum)
            {
                while select vendPaymentUploadLoc 
                    where vendPaymentUploadLoc.SettlementNumberSequence == vendPaymentUpload.SettlementNumberSequence &&
                    vendPaymentUploadLoc.Posted 
                    && !vendPaymentUploadLoc.Reversed
                {
                    select firstonly payVendTrans where payVendTrans.Voucher == vendPaymentUploadLoc.Voucher;

                    settlementDate = vendPaymentUpload.SettlementDate;
                    select * from vendSettlement
                    where vendSettlement.TransRecId == payVendTrans.RecId &&
                    vendSettlement.TransCompany  == payVendTrans.DataAreaId &&
                    vendSettlement.AccountNum    == payVendTrans.AccountNum &&
                    vendSettlement.CanBeReversed == NoYes::Yes &&
                    vendSettlement.TransDate == settlementDate;
                    {
                        vendTable   = VendTable::find(payVendTrans.AccountNum);

                        specTransManager = SpecTransManager::newRefTableId(vendTable, tablenum(vendSettlement), true);

                        specTransManager.insert(vendSettlement.DataAreaId
                                            , vendSettlement.TableId
                                            , vendSettlement.RecId
                                            , vendSettlement.SettleAmountCur
                                            , payVendTrans.CurrencyCode);

                        vendSettlement.CustVendSettlement::markThisAndRelatedOffsets(specTransManager, payVendTrans.CurrencyCode);

                        if (VendTrans::reverseTransact(vendTable, null, settleDatePrinc::SelectDate, settlementDate))
                        {
                            specTransManager.deleteAll();
                            undo = true;
                        }
                    }
                    if(undo)
                    {
                        {
                            vendPaymentUploadLoc.selectForUpdate(true);
                            vendPaymentUploadLoc.Reversed = NoYes::Yes;
                            vendPaymentUploadLoc.update();
                        }
                    }
                    settleSeqNum = vendPaymentUploadLoc.SettlementNumberSequence;
                }
            }
            vendPaymentUpload = selectionHelper.getNext();
        }
    }
    else
    {
        throw error("@ETG_New:PaymentUploaderTransactionSettlement");
    }
    info("@ETG_New:PaymentUploaderUndoSettlement");
    ttscommit;
    ETGPaymentUploaderTable_ds.research(true);
}

/// <summary>
///
/// </summary>
public void init()
{
    super();

    QueryBuildDataSource paymentUploaderQBDS = this.query().dataSourceTable(tableNum(ETGPaymentUploaderTable));
    QueryBuildRange accountTypeRange = SysQuery::findOrCreateRange(paymentUploaderQBDS, fieldNum(ETGPaymentUploaderTable,AccountType));

    switch(moduleCustVend)
    {
        case ModuleCustVend::Vend:
            accountTypeRange.value(enum2str(ModuleCustVend::Vend));
            break;

        case ModuleCustVend::Cust:
            accountTypeRange.value(enum2str(ModuleCustVend::Cust));
            break;
    }

    paymentUploaderQBDS.addSortField(fieldNum(ETGPaymentUploaderTable,SettlementNumberSequence ),SortOrder::Ascending);
}

/// <summary>
///
/// </summary>
public void clicked()
{
    super();

    switch(moduleCustVend)
    {
        case ModuleCustVend::Vend:
            element.vendSettleTransaction();
            break;

        case ModuleCustVend::Cust:
            element.custSettleTransaction();
            break;
    }
}

        /// <summary>
        ///
        /// </summary>
        public void clicked()
        {
            MultiSelectionHelper selectionHelper = MultiSelectionHelper::construct();//Create instance of class
            Set selectedRecords = new Set(Types::Record);//Declare a set of type record

            super();

            ETGPaymentUploaderTable     paymentUpload, paymentUploadLoc;
            boolean                     validate = true;
            real                        totalAmount;
            CurrencyCode                curr;
            int                         settlementNum, invoiceCount, paymentCount;
            VendTrans                   invVendTrans, payVendTrans;
            VendTransOpen               invVendTransOpen, payVendTransOpen;
            CustTrans                   invCustTrans, payCustTrans;
            CustTransOpen               invCustTransOpen, payCustTransOpen;

            selectionHelper.parmDataSource(ETGPaymentUploaderTable_ds);   //Set the datasource

            paymentUpload = selectionHelper.getFirst();

            if(paymentUpload.RecId)
            {
                while(paymentUpload)
                {
                    if(paymentUpload.SettlementNumber != settlementNum)
                    {
                        curr = '';
                        invoiceCount = 0;
                        paymentCount = 0;
                        while select paymentUploadLoc 
                            where paymentUploadLoc.SettlementNumber == paymentUpload.SettlementNumber &&
                            !paymentUploadLoc.SettlementNumberSequence
                        {
                            if(paymentUploadLoc.AccountType == ModuleCustVend::Cust)
                            {
                                select firstonly invCustTrans
                                    where invCustTrans.Voucher == paymentUploadLoc.Voucher &&
                                        invCustTrans.AmountCur > 0
                                    join invCustTransOpen
                                    where invCustTransOpen.RefRecId == invCustTrans.RecId;

                                if(invCustTransOpen)
                                {
                                    invoiceCount++;
                                }

                                select firstonly payCustTrans
                                    where payCustTrans.Voucher == paymentUploadLoc.Voucher &&
                                        payCustTrans.AmountCur < 0
                                    join payCustTransOpen
                                    where payCustTransOpen.RefRecId == payCustTrans.RecId;

                                if(payCustTransOpen)
                                {
                                    paymentCount++;
                                }
                            }
                            else if(paymentUploadLoc.AccountType == ModuleCustVend::Vend)
                            {
                                select firstonly invVendTrans
                                where invVendTrans.Voucher == paymentUploadLoc.Voucher &&
                                    invVendTrans.AmountCur < 0
                                join invVendTransOpen
                                where invVendTransOpen.RefRecId == invVendTrans.RecId;

                                if(invVendTransOpen)
                                {
                                    invoiceCount++;
                                }

                                select firstonly payVendTrans
                                where payVendTrans.Voucher == paymentUploadLoc.Voucher &&
                                    payVendTrans.AmountCur > 0
                                join payVendTransOpen
                                where payVendTransOpen.RefRecId == payVendTrans.RecId;

                                if(payVendTransOpen)
                                {
                                    paymentCount++;
                                }

                                //
                                if(paymentUpload.SettlementDate < paymentUpload.TransDate  )
                                {
                                    throw error(strFmt('Settlement date should be greater than or equal to Trans Date Voucher: %1',paymentUpload.Voucher));
                                }
                                else if(paymentUploadLoc.SettlementDate < paymentUploadLoc.TransDate)
                                {
                                    throw error(strFmt('Settlement date should be greater than or equal to Trans Date Voucher: %1',paymentUploadLoc.Voucher));

                                }

                            }
                            if((curr && paymentUploadLoc.CurrencyCode != curr) && !paymentUploadLoc.Posted)
                            {
                                validate = false;
                                throw error(strFmt("@ETG_New:PaymentUploaderCurrencymismatchError"));
                            }
                            if(abs(paymentUploadLoc.SettlementAmount) > abs(paymentUploadLoc.remainAmountCur()))
                            {
                                validate = false;
                                throw error(strFmt("@ETG_New:PaymentUploaderSettlementAmountError",paymentUploadLoc.Voucher));
                            }
                            totalAmount     = totalAmount + paymentUploadLoc.SettlementAmount;
                            curr            = paymentUploadLoc.CurrencyCode;
                            settlementNum   = paymentUploadLoc.SettlementNumber;
                        }
                        if(invoiceCount <= 0 ||  paymentCount <= 0)
                        {
                            throw error(strFmt("@ETG_New:PaymentUploaderTransactionError",paymentUploadLoc.SettlementNumber));
                        }
                        if(totalAmount != 0)
                        {
                            validate = false;
                            throw error(strFmt("@ETG_New:PaymentUploaderTotalSettlementAmountError"));
                        }
                    }
                    paymentUpload = selectionHelper.getNext();
                }
            }
            paymentUploadLoc = selectionHelper.getFirst();

            if(paymentUploadLoc.RecId && validate)
            {
                ttsbegin;
                while(paymentUploadLoc)
                {
                    paymentUploadLoc.selectForUpdate();
                    paymentUploadLoc.Validated = NoYes::Yes;
                    paymentUploadLoc.update();
                    paymentUploadLoc   = selectionHelper.getNext();
;               }
                ttscommit;
            }
            info("@ETG_New:PaymentUploaderValidation");
            ETGPaymentUploaderTable_ds.research(true);
        }

/// <summary>
