}

/// <summary>
///
/// </summary>
public void jumpRef()
{
    str accountNum = ETGPaymentUploaderTable_AccountNum.valueStr();

    super();

    switch(moduleCustVend)
    {
        case ModuleCustVend::Vend:
            VendTable vend = VendTable::find(accountNum);
            Args vendArgs = new Args();
            vendArgs.record(vend); // Pass the found record
            vendArgs.lookupRecord(vend); // Set the record as the current lookup record
            // Open the target form with the record
            MenuFunction vendMenuFunction;
            vendMenuFunction = new MenuFunction(menuitemDisplayStr(VendTable), MenuItemType::Display);
            vendMenuFunction.run(vendArgs);
            break;

        case ModuleCustVend::Cust:
            CustTable cust = CustTable::find(accountNum);
            Args custArgs = new Args();
            custArgs.record(cust); // Pass the found record
            custArgs.lookupRecord(cust); // Set the record as the current lookup record
            // Open the target form with the record
            MenuFunction custMenuFunction;
            custMenuFunction = new MenuFunction(menuitemDisplayStr(CustTable), MenuItemType::Display);
            custMenuFunction.run(custArgs);
            break;
    }
}

/// <summary>
///
/// </summary>
public void jumpRef()
{
    str voucher = ETGPaymentUploaderTable_Voucher.valueStr();

    super();

    switch(moduleCustVend)
    {
        case ModuleCustVend::Vend:
            VendTrans vend;
            select * from vend where vend.Voucher == voucher;
            Args vendArgs = new Args();
            vendArgs.record(vend); // Pass the found record
            // Open the target form with the record
            MenuFunction vendMenuFunction;
            vendMenuFunction = new MenuFunction(menuitemDisplayStr(VendTrans), MenuItemType::Display);
            vendMenuFunction.run(vendArgs);
            break;

        case ModuleCustVend::Cust:
            CustTrans cust = CustTrans::findByVoucher(voucher);
            Args custArgs = new Args();
            custArgs.record(cust); // Pass the found record
            // Open the target form with the record
            MenuFunction custMenuFunction;
            custMenuFunction = new MenuFunction(menuitemDisplayStr(CustTrans), MenuItemType::Display);
            custMenuFunction.run(custArgs);
            break;
    }
}
